#include <stdio.h>
#include <stdlib.h>

// Structure for a graph
typedef struct Graph {
    int V;
    int **adj;
} Graph;

// Function to create a graph
Graph* createGraph(int V) {
    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->V = V;
    graph->adj = (int**)malloc(V * sizeof(int*));
    for (int i = 0; i < V; i++) {
        graph->adj[i] = (int*)malloc(V * sizeof(int));
        for (int j = 0; j < V; j++) {
            graph->adj[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adj[u][v] = 1;
}

// Function to perform DFS
void DFS(Graph* graph, int vertex, int* visited, int* stack, int* top) {
    visited[vertex] = 1;
    for (int i = 0; i < graph->V; i++) {
        if (graph->adj[vertex][i] && !visited[i]) {
            DFS(graph, i, visited, stack, top);
        }
    }
    stack[++(*top)] = vertex;
}

// Function to perform DFS on the transposed graph
void DFS2(Graph* graph, int vertex, int* visited) {
    visited[vertex] = 1;
    for (int i = 0; i < graph->V; i++) {
        if (graph->adj[i][vertex] && !visited[i]) {
            DFS2(graph, i, visited);
        }
    }
}

// Function to find strongly connected components
int kosaraju(Graph* graph) {
    int* visited = (int*)malloc(graph->V * sizeof(int));
    int* stack = (int*)malloc(graph->V * sizeof(int));
    int top = -1;
    for (int i = 0; i < graph->V; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph->V; i++) {
        if (!visited[i]) {
            DFS(graph, i, visited, stack, &top);
        }
    }
    Graph* transpose = createGraph(graph->V);
    for (int i = 0; i < graph->V; i++) {
        for (int j = 0; j < graph->V; j++) {
            if (graph->adj[i][j]) {
                addEdge(transpose, j, i);
            }
        }
    }
    for (int i = 0; i < graph->V; i++) {
        visited[i] = 0;
    }
    int count = 0;
    while (top >= 0) {
        int vertex = stack[top--];
        if (!visited[vertex]) {
            DFS2(transpose, vertex, visited);
            count++;
        }
    }
    return count;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Graph* graph = createGraph(V);
    for (int i = 0; i < E; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u, v);
    }
    printf("%d\n", kosaraju(graph));
    return 0;
}

